-- Seed 55+ realistic Ukrainian grants
-- All deadlines are in the future (2026-2027)

INSERT OR IGNORE INTO "Grant" (id, title, description, fullText, amount, amountUsd, deadline, sourceUrl, source, category, region, sphere, status, score, createdAt, updatedAt, publishedAt)
VALUES

-- ТЕХНОЛОГІЇ (10 grants)
('g01_ai_manufacturing', 'Грант ЄС на цифровізацію виробництва до €150,000', 'Програма Digital Europe для українських виробничих підприємств, що впроваджують автоматизацію, робототехніку та системи управління якістю на базі штучного інтелекту.', 'Програма Digital Europe надає фінансування українським виробничим підприємствам для впровадження цифрових рішень. Гранти покривають витрати на придбання обладнання для автоматизації, програмного забезпечення для управління виробництвом, систем контролю якості на базі AI, а також навчання персоналу. Підприємство має бути зареєстроване не менше 2 років та мати щорічний оборот від 500,000 грн. Фінансування надається на умовах співфінансування 70/30.', 'до €150,000', 150000, '2026-06-15', 'https://grants.eu/digital-europe-ua-01', 'EU Digital Europe', 'Технології', 'Вся Україна', 'Автоматизація виробництва', 'APPROVED', 88, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g02_cybersecurity', 'Кібербезпека для бізнесу: грант до 500,000 грн', 'Державна програма підвищення кіберстійкості малого та середнього бізнесу. Покриває аудит безпеки, впровадження захисних систем та навчання персоналу.', 'Програма Мінцифри спрямована на підвищення рівня кібербезпеки українського бізнесу. Грант покриває проведення аудиту інформаційної безпеки, впровадження систем захисту від кібератак, навчання співробітників основам кібергігієни, а також сертифікацію за міжнародними стандартами ISO 27001. Пріоритет надається підприємствам критичної інфраструктури та компаніям, що працюють з персональними даними.', 'до 500,000 грн', 12000, '2026-08-30', 'https://mintsyfra.gov.ua/cyber-grant-01', 'Мінцифри', 'Технології', 'Вся Україна', 'Кібербезпека', 'APPROVED', 82, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g03_edtech', 'EdTech стартапи: інвестиції до $300,000', 'Міжнародний акселератор для стартапів у сфері освітніх технологій. Включає менторство від Google та Microsoft, доступ до хмарних ресурсів та пілотування в українських школах.', 'Програма EdTech Accelerator Ukraine підтримує стартапи, що розробляють інноваційні рішення для освіти. Учасники отримують фінансування до $300,000, менторську підтримку від провідних міжнародних компаній, безкоштовний доступ до хмарних ресурсів Azure та GCP, а також можливість пілотного впровадження у 50+ українських навчальних закладах. Стартап має мати MVP та перших користувачів.', 'до $300,000', 300000, '2026-07-20', 'https://edtech-accelerator.ua/apply', 'EdTech Hub Ukraine', 'Технології', 'Вся Україна', 'Освітні технології', 'APPROVED', 91, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g04_iot_agro', 'IoT для точного землеробства: грант до €80,000', 'Програма USAID для впровадження IoT-сенсорів, дронів та систем моніторингу ґрунту в аграрних господарствах України.', 'USAID спільно з Мінагрополітики запускає програму підтримки впровадження технологій точного землеробства. Грант покриває витрати на IoT-сенсори для моніторингу вологості, температури та складу ґрунту, безпілотні літальні апарати для обстеження полів, програмне забезпечення для аналізу даних та прийняття рішень. Пріоритет — фермерські господарства з площею від 50 га.', 'до €80,000', 80000, '2026-09-15', 'https://usaid.gov/ukraine/iot-agro-01', 'USAID', 'Технології', 'Вся Україна', 'AgriTech', 'APPROVED', 85, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g05_fintech', 'FinTech Innovation Lab: грант до €200,000', 'Програма НБУ та ЄС для фінтех-стартапів. Розробка інноваційних платіжних рішень, необанкінг, блокчейн-технології для фінансового сектору.', 'Спільна програма Національного банку України та Європейського Союзу підтримує розвиток фінансових технологій в Україні. Грант надається на розробку інноваційних платіжних систем, рішень для необанкінгу, застосування блокчейн-технологій у фінансовому секторі, а також розвиток RegTech та InsurTech рішень. Стартап має мати юридичну реєстрацію в Україні та команду від 3 осіб.', 'до €200,000', 200000, '2026-10-01', 'https://nbu.gov.ua/fintech-lab-grant', 'НБУ / EU4Business', 'Технології', 'Вся Україна', 'Фінансові технології', 'APPROVED', 87, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g06_healthtech', 'HealthTech: грант до €120,000 на медичні інновації', 'Програма WHO та МОЗ для стартапів у сфері цифрової медицини. Телемедицина, AI-діагностика, електронні медичні записи, носимі пристрої.', 'Всесвітня організація охорони здоров''я спільно з МОЗ України фінансує розробку цифрових рішень для медицини. Пріоритетні напрямки: телемедичні платформи для віддалених регіонів, AI-системи для ранньої діагностики захворювань, рішення для електронних медичних записів, розробка носимих медичних пристроїв. Обов''язкова вимога — співпраця з медичним закладом-партнером.', 'до €120,000', 120000, '2026-08-15', 'https://who.int/ukraine/healthtech-grant', 'WHO / МОЗ', 'Технології', 'Вся Україна', 'Цифрова медицина', 'APPROVED', 89, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g07_ecommerce', 'Грант на розвиток e-commerce до 300,000 грн', 'Програма Мінекономіки для виходу українських виробників на міжнародні маркетплейси. Покриває створення онлайн-магазинів, маркетинг та логістику.', 'Мінекономіки надає гранти українським виробникам для розвитку електронної комерції. Фінансування покриває створення інтернет-магазинів, вихід на міжнародні маркетплейси (Amazon, Etsy, eBay), розробку маркетингових стратегій, оптимізацію логістичних процесів для міжнародних відправок. Пріоритет надається виробникам hand-made товарів, органічної продукції та традиційних українських виробів.', 'до 300,000 грн', 7200, '2026-07-30', 'https://me.gov.ua/ecommerce-grant', 'Мінекономіки', 'Технології', 'Вся Україна', 'E-commerce', 'APPROVED', 78, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g08_gamedev', 'Game Dev Ukraine: грант до $150,000', 'Акселератор для українських геймдев-студій. Фінансування розробки ігор, менторство від ветеранів індустрії, доступ до видавців та інвесторів.', 'Програма Game Dev Ukraine підтримує розвиток української індустрії розробки ігор. Грант покриває витрати на розробку прототипів та демо-версій, оплату праці команди, придбання ліцензій на ігрові движки та інструменти, участь у міжнародних виставках (GDC, Gamescom). Додатково надається менторство від досвідчених розробників та доступ до мережі видавців.', 'до $150,000', 150000, '2026-11-30', 'https://gamedev-ua.com/grant-2026', 'GameDev Ukraine Fund', 'Технології', 'Вся Україна', 'Ігрова індустрія', 'APPROVED', 83, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g09_saas_b2b', 'B2B SaaS стартапи: грант ЄБРР до €250,000', 'Програма ЄБРР для B2B SaaS стартапів з українським корінням. Масштабування на європейський ринок, побудова каналів продажів та партнерства.', 'Європейський банк реконструкції та розвитку надає гранти українським B2B SaaS стартапам для масштабування на європейських ринках. Фінансування покриває розвиток продукту, побудову каналів продажів в ЄС, локалізацію продукту, отримання необхідних сертифікацій та відповідність GDPR. Стартап має демонструвати MRR від $5,000 та мати product-market fit.', 'до €250,000', 250000, '2026-09-30', 'https://ebrd.com/ukraine-saas-grant', 'ЄБРР', 'Технології', 'Вся Україна', 'SaaS / B2B', 'APPROVED', 90, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g10_blockchain', 'Blockchain for Good: грант до €100,000', 'Програма UNICEF для блокчейн-проєктів із соціальним впливом. Прозорість благодійності, цифрова ідентифікація, відстеження гуманітарної допомоги.', 'UNICEF Innovation Fund підтримує проєкти, що використовують блокчейн-технології для соціального блага. Пріоритетні напрямки: системи прозорого розподілу гуманітарної допомоги, цифрова ідентифікація для внутрішньо переміщених осіб, платформи для прозорої благодійності, рішення для відстеження ланцюгів постачання соціально значущих товарів. Проєкт має бути open-source.', 'до €100,000', 100000, '2026-12-15', 'https://unicef.org/innovation/blockchain-ua', 'UNICEF Innovation', 'Технології', 'Вся Україна', 'Блокчейн', 'APPROVED', 84, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

-- ПІДПРИЄМНИЦТВО (10 grants)
('g11_women_biz', 'Жінки в бізнесі: грант до €50,000', 'Програма UN Women для підтримки жіночого підприємництва. Стартовий капітал, менторство, навчання та нетворкінг для жінок-підприємниць.', 'UN Women та Уряд Швеції фінансують програму підтримки жіночого підприємництва в Україні. Грант покриває стартовий капітал, обладнання, навчальні програми з менеджменту та маркетингу, менторську підтримку від успішних підприємниць, а також участь у бізнес-форумах. Пріоритет — жінки з сільської місцевості, ВПО та жінки-ветеранки.', 'до €50,000', 50000, '2026-08-01', 'https://unwomen.org/ukraine-women-biz', 'UN Women', 'Підприємництво', 'Вся Україна', 'Жіноче підприємництво', 'APPROVED', 86, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g12_veterans_biz', 'єВідновлення для ветеранів: грант до 1 млн грн', 'Державна програма підтримки підприємництва серед ветеранів. Бізнес-навчання, грантове фінансування та супровід протягом першого року.', 'Програма Мінветеранів надає комплексну підтримку ветеранам, які бажають розпочати власну справу. Включає безкоштовне бізнес-навчання (3 місяці), грантове фінансування до 1,000,000 грн, індивідуальний супровід бізнес-консультанта протягом першого року, пільговий доступ до коворкінгів та бізнес-інкубаторів. Заявник має бути ветераном або членом сім''ї загиблого захисника.', 'до 1,000,000 грн', 24000, '2026-12-31', 'https://mva.gov.ua/veterans-biz-grant', 'Мінветеранів', 'Підприємництво', 'Вся Україна', 'Ветеранське підприємництво', 'APPROVED', 94, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g13_social_enterprise', 'Соціальне підприємництво: грант до €75,000', 'Програма British Council для соціальних підприємств. Бізнес-моделі з подвійним ефектом — прибуток та соціальний вплив.', 'British Council Ukraine надає гранти соціальним підприємствам, що поєднують комерційну діяльність із вирішенням соціальних проблем. Фінансування покриває розвиток продукту/послуги, маркетинг, обладнання та найм персоналу. Пріоритетні напрямки: працевлаштування людей з інвалідністю, екологічні ініціативи, підтримка вразливих груп населення, розвиток громад. Підприємство має мати вимірюваний соціальний вплив.', 'до €75,000', 75000, '2026-07-15', 'https://britishcouncil.org.ua/social-enterprise', 'British Council', 'Підприємництво', 'Вся Україна', 'Соціальне підприємництво', 'APPROVED', 81, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g14_franchise', 'Франшиза під ключ: грант до 400,000 грн', 'Програма ПРООН для відкриття бізнесу за моделлю франчайзингу. Покриває франчайзинговий внесок, обладнання та перші місяці операційних витрат.', 'ПРООН спільно з Мінекономіки надає гранти для відкриття бізнесу за моделлю франчайзингу. Грант покриває франчайзинговий внесок, придбання обладнання згідно стандартів франшизи, ремонт та облаштування приміщення, операційні витрати на перші 3 місяці роботи. Перевага надається заявникам з деокупованих та прифронтових територій.', 'до 400,000 грн', 9600, '2026-06-30', 'https://undp.org/ukraine/franchise-grant', 'ПРООН', 'Підприємництво', 'Вся Україна', 'Франчайзинг', 'APPROVED', 79, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g15_youth_startup', 'Молодіжний стартап: грант до 200,000 грн', 'Програма Мінмолоді для підприємців віком 18-35 років. Бізнес-ідеї в будь-якій сфері, конкурсний відбір, менторська підтримка.', 'Програма підтримки молодіжного підприємництва від Мінмолоді та UNFPA. Грант до 200,000 грн надається молодим підприємцям віком 18-35 років на реалізацію бізнес-ідей у будь-якій сфері. Конкурсний відбір включає подання бізнес-плану, захист перед журі та онлайн-голосування. Переможці також отримують менторську підтримку та доступ до бізнес-інкубатора.', 'до 200,000 грн', 4800, '2026-05-31', 'https://minmolod.gov.ua/youth-startup', 'Мінмолоді', 'Підприємництво', 'Вся Україна', 'Молодіжне підприємництво', 'APPROVED', 77, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g16_export_support', 'Експортний грант до €100,000', 'Програма EU4Business для українських експортерів. Сертифікація продукції, участь у виставках, маркетингові дослідження зарубіжних ринків.', 'EU4Business надає гранти українським компаніям для розвитку експортного потенціалу. Фінансування покриває отримання міжнародних сертифікацій (CE, ISO, HACCP), участь у міжнародних виставках та trade-місіях, маркетингові дослідження цільових ринків, адаптацію продукції до вимог ЄС, створення іншомовних маркетингових матеріалів. Компанія має мати досвід продажів на внутрішньому ринку від 1 року.', 'до €100,000', 100000, '2026-10-15', 'https://eu4business.org.ua/export-grant', 'EU4Business', 'Підприємництво', 'Вся Україна', 'Експорт', 'APPROVED', 86, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g17_creative_hub', 'Грант на створення креативного хабу до 2 млн грн', 'Програма Українського культурного фонду для створення креативних просторів, коворкінгів та мейкерспейсів у регіонах.', 'Український культурний фонд фінансує створення креативних просторів у регіонах України. Грант покриває ремонт та облаштування приміщення, придбання обладнання (3D-принтери, лазерні різаки, звукозаписуюче обладнання), меблі, IT-інфраструктуру. Простір має бути відкритий для місцевої громади та проводити не менше 4 публічних заходів на місяць.', 'до 2,000,000 грн', 48000, '2026-06-20', 'https://ucf.org.ua/creative-hub-grant', 'УКФ', 'Підприємництво', 'Регіони', 'Креативні індустрії', 'APPROVED', 80, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g18_rural_biz', 'Сільський бізнес: грант до 500,000 грн', 'Програма FAO для розвитку несільськогосподарського бізнесу в сільській місцевості. Зелений туризм, переробка, народні промисли.', 'FAO та Мінагрополітики надають гранти для диверсифікації сільської економіки. Фінансуються проєкти зеленого туризму (садиби, екскурсії, гастротури), переробки місцевої сировини (сири, мед, варення, копченості), народних промислів (гончарство, вишивка, ткацтво), надання послуг (ремонт, освіта, побутові послуги). Заявник має бути зареєстрований у сільській місцевості.', 'до 500,000 грн', 12000, '2026-08-31', 'https://fao.org/ukraine/rural-biz', 'FAO / Мінагро', 'Підприємництво', 'Сільська місцевість', 'Сільський розвиток', 'APPROVED', 76, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g19_startup_visa', 'Startup Visa Poland: грант до €40,000', 'Програма для українських стартапів з можливістю виходу на ринок Польщі. Резидентура, менторство та фінансування від польських інвесторів.', 'Програма Startup Visa Poland пропонує українським стартапам можливість резидентури в Польщі з грантовим фінансуванням. Включає робочий простір у Варшаві або Кракові, менторство від польських підприємців, доступ до мережі ангельських інвесторів, юридичну підтримку для реєстрації компанії в Польщі. Стартап має бути на стадії pre-seed або seed.', 'до €40,000', 40000, '2026-07-01', 'https://startup-visa.pl/ukraine', 'PFR / Polish Dev Fund', 'Підприємництво', 'Вся Україна', 'Міжнародна експансія', 'APPROVED', 82, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g20_food_biz', 'Переробка продуктів: грант до 800,000 грн', 'Програма GIZ для розвитку харчової промисловості. Обладнання для переробки, пакування, сертифікація HACCP та вихід на нові ринки.', 'GIZ надає гранти для розвитку малих та середніх підприємств харчової промисловості. Фінансування покриває обладнання для переробки та пакування, отримання сертифікації HACCP та ISO 22000, розробку нових продуктів, лабораторні дослідження, маркетинг та брендинг. Пріоритет — підприємства, що використовують місцеву сировину та створюють робочі місця.', 'до 800,000 грн', 19200, '2026-09-01', 'https://giz.de/ukraine/food-processing', 'GIZ', 'Підприємництво', 'Вся Україна', 'Харчова промисловість', 'APPROVED', 83, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

-- ЕКОЛОГІЯ (8 grants)
('g21_solar_energy', 'Сонячна енергетика: грант до €300,000', 'Програма ЄБРР для встановлення сонячних панелей на комерційних об''єктах. Зменшення вуглецевого сліду та енергетична незалежність.', 'ЄБРР фінансує проєкти з встановлення сонячних електростанцій на комерційних та промислових об''єктах. Грант покриває вартість обладнання (панелі, інвертори, акумулятори), проєктування та монтаж, підключення до мережі та оформлення зеленого тарифу. Потужність станції має бути від 30 кВт. Програма також включає технічний супровід та навчання персоналу.', 'до €300,000', 300000, '2026-11-01', 'https://ebrd.com/ukraine-solar-grant', 'ЄБРР / Green Energy', 'Екологія', 'Вся Україна', 'Відновлювана енергетика', 'APPROVED', 88, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g22_waste_recycling', 'Переробка відходів: грант до €200,000', 'Програма NEFCO для створення або модернізації сортувальних ліній, пунктів прийому вторсировини та об''єктів переробки.', 'NEFCO фінансує проєкти з управління відходами в Україні. Грант покриває будівництво або модернізацію сортувальних ліній, створення пунктів прийому вторсировини, обладнання для переробки пластику, скла, паперу та органічних відходів. Також фінансуються освітні кампанії для населення та розробка логістичних маршрутів збору відходів. Проєкт має обслуговувати територію з населенням від 10,000 осіб.', 'до €200,000', 200000, '2026-10-15', 'https://nefco.org/ukraine-waste-management', 'NEFCO', 'Екологія', 'Вся Україна', 'Управління відходами', 'APPROVED', 85, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g23_water_treatment', 'Очистка води: грант до €500,000', 'Програма Світового банку для модернізації систем водоочищення та водопостачання у малих містах та селах.', 'Світовий банк та Мінрегіон фінансують модернізацію систем водоочищення в малих громадах України. Грант покриває обладнання для очистки питної води, реконструкцію водопровідних мереж, встановлення автоматизованих систем контролю якості води, будівництво свердловин та водонапірних веж. Громада має мати затверджений план розвитку та забезпечити 10% співфінансування.', 'до €500,000', 500000, '2026-12-01', 'https://worldbank.org/ukraine-water', 'Світовий банк', 'Екологія', 'Малі міста та села', 'Водопостачання', 'APPROVED', 92, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g24_eco_packaging', 'Еко-пакування: грант до €60,000', 'Програма WWF для переходу на біорозкладні та повторно використовувані пакувальні матеріали.', 'WWF Ukraine фінансує проєкти з переходу на екологічне пакування. Грант покриває розробку та тестування біорозкладних пакувальних матеріалів, адаптацію виробничих ліній, сертифікацію еко-пакування, маркетинг та комунікацію зі споживачами. Пріоритет — виробники продуктів харчування та напоїв, компанії e-commerce, заклади громадського харчування.', 'до €60,000', 60000, '2026-07-31', 'https://wwf.ua/eco-packaging-grant', 'WWF Ukraine', 'Екологія', 'Вся Україна', 'Еко-пакування', 'APPROVED', 79, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g25_green_building', 'Зелене будівництво: грант до €400,000', 'Програма IFC для впровадження стандартів зеленого будівництва. Енергоефективність, використання екоматеріалів, BREEAM/LEED сертифікація.', 'IFC (група Світового банку) надає гранти для будівельних компаній, що впроваджують стандарти зеленого будівництва. Фінансування покриває проєктування за стандартами BREEAM або LEED, використання енергоефективних матеріалів та технологій, встановлення систем рекуперації тепла, збору дощової води та сонячних панелей. Проєкт має бути житловим або комерційним будівництвом площею від 1000 кв.м.', 'до €400,000', 400000, '2027-03-01', 'https://ifc.org/ukraine-green-building', 'IFC', 'Екологія', 'Вся Україна', 'Зелене будівництво', 'APPROVED', 87, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g26_urban_greening', 'Озеленення міст: грант до 1,500,000 грн', 'Програма ДФРР для створення парків, скверів та зелених зон у містах. Висадка дерев, створення велодоріжок та зон відпочинку.', 'Державний фонд регіонального розвитку фінансує проєкти озеленення українських міст. Грант покриває ландшафтний дизайн та проєктування, висадку дерев та кущів, створення велодоріжок та пішохідних зон, встановлення вуличних меблів та освітлення, системи автоматичного поливу. Проєкт має бути узгоджений з міською владою та мати підтримку громади.', 'до 1,500,000 грн', 36000, '2026-06-15', 'https://dfrr.gov.ua/urban-greening', 'ДФРР', 'Екологія', 'Міста України', 'Міський розвиток', 'APPROVED', 74, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g27_ev_infrastructure', 'Зарядні станції для EV: грант до €150,000', 'Програма EIB для розбудови мережі зарядних станцій для електромобілів вздовж основних автомагістралей.', 'Європейський інвестиційний банк фінансує розбудову мережі зарядних станцій для електромобілів в Україні. Грант покриває обладнання (швидкі зарядки DC 50-150 кВт), будівельні роботи, підключення до електромережі, програмне забезпечення для управління та оплати. Станція має розташовуватися вздовж основних автомагістралей з відстанню не менше 50 км від найближчої існуючої зарядки.', 'до €150,000', 150000, '2026-09-30', 'https://eib.org/ukraine-ev-charging', 'EIB', 'Екологія', 'Вся Україна', 'Електротранспорт', 'APPROVED', 86, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g28_organic_farming', 'Органічне фермерство: грант до €90,000', 'Програма Швейцарії для переходу на органічне виробництво. Сертифікація, обладнання, навчання та доступ до ринків збуту.', 'Швейцарське агентство розвитку SDC фінансує перехід українських фермерських господарств на органічне виробництво. Грант покриває витрати на органічну сертифікацію, перехідний період (2-3 роки), придбання біопрепаратів та органічних добрив, обладнання для переробки, участь у органічних виставках та ярмарках. Господарство має мати від 5 га сільськогосподарських угідь.', 'до €90,000', 90000, '2026-08-15', 'https://sdc.admin.ch/ukraine-organic', 'SDC Швейцарія', 'Екологія', 'Вся Україна', 'Органічне виробництво', 'APPROVED', 81, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

-- АГРОСЕКТОР (7 grants)
('g29_greenhouse', 'Тепличне господарство: грант до 3 млн грн', 'Програма ФАО для будівництва сучасних теплиць з автоматизованим управлінням мікрокліматом та системами крапельного поливу.', 'ФАО та Мінагрополітики фінансують будівництво сучасних тепличних комплексів. Грант покриває будівельні роботи, системи автоматизованого управління мікрокліматом, краплинне зрошення, LED-освітлення, системи рекуперації тепла. Також фінансуються навчальні програми для персоналу та розробка бізнес-планів збуту продукції. Пріоритет — вирощування овочів та зелені для місцевих ринків.', 'до 3,000,000 грн', 72000, '2026-10-01', 'https://fao.org/ukraine/greenhouse-grant', 'FAO', 'Агросектор', 'Вся Україна', 'Тепличне виробництво', 'APPROVED', 84, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g30_dairy', 'Молочна ферма: грант до €180,000', 'Програма DANIDA для модернізації молочних ферм. Доїльне обладнання, охолоджувачі молока, системи утилізації відходів.', 'Данське агентство міжнародного розвитку DANIDA фінансує модернізацію молочних ферм в Україні. Грант покриває сучасне доїльне обладнання, танки-охолоджувачі молока, системи утилізації гною та виробництва біогазу, обладнання для первинної переробки (пастеризація, фасування). Ферма має утримувати від 30 голів великої рогатої худоби.', 'до €180,000', 180000, '2026-11-15', 'https://danida.dk/ukraine-dairy', 'DANIDA', 'Агросектор', 'Вся Україна', 'Молочне виробництво', 'APPROVED', 82, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g31_berry_farming', 'Ягідництво: грант до 1,200,000 грн', 'Програма для закладення ягідних плантацій. Саджанці, системи крапельного зрошення, холодильне обладнання та лінії сортування.', 'Мінагрополітики спільно з IFC фінансує розвиток ягідництва в Україні. Грант покриває придбання сертифікованих саджанців (полуниця, малина, лохина, ожина), встановлення систем крапельного зрошення, холодильного обладнання для зберігання, ліній сортування та пакування. Пріоритет — господарства в західних та центральних областях з площею від 2 га.', 'до 1,200,000 грн', 28800, '2026-04-15', 'https://minagro.gov.ua/berry-grant', 'Мінагро / IFC', 'Агросектор', 'Західна та Центральна Україна', 'Ягідництво', 'APPROVED', 78, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g32_beekeeping', 'Бджільництво: грант до 350,000 грн', 'Програма підтримки бджільництва. Вулики, обладнання для відкачки та фасування меду, лабораторний аналіз та органічна сертифікація.', 'Спільна програма ФАО та Мінагрополітики підтримує розвиток бджільництва в Україні. Фінансування покриває придбання вуликів та бджолосімей, обладнання для відкачки, фільтрації та фасування меду, лабораторний аналіз продукції, органічну сертифікацію, участь у виставках та ярмарках. Пасіка має налічувати від 20 бджолосімей або заявник планує створити нову пасіку.', 'до 350,000 грн', 8400, '2026-05-01', 'https://fao.org/ukraine/beekeeping', 'FAO / Мінагро', 'Агросектор', 'Вся Україна', 'Бджільництво', 'APPROVED', 75, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g33_aquaculture', 'Аквакультура: грант до €120,000', 'Програма для розведення риби та інших водних організмів. Ставки, УЗВ-системи, корми, мальки та обладнання для переробки.', 'Норвезький фонд розвитку фінансує проєкти аквакультури в Україні. Грант покриває будівництво або реконструкцію ставків, встановлення систем рециркуляції води (УЗВ), придбання мальків цінних порід риб, кормів, обладнання для первинної переробки та заморозки. Також фінансуються навчальні поїздки до Норвегії для обміну досвідом.', 'до €120,000', 120000, '2026-09-15', 'https://norway-grants.ua/aquaculture', 'Норвезький фонд', 'Агросектор', 'Вся Україна', 'Аквакультура', 'APPROVED', 80, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g34_agro_processing', 'Переробка зерна: грант до 5 млн грн', 'Програма для будівництва міні-елеваторів, млинів, комбікормових заводів. Зберігання, сушіння та переробка зернових.', 'Мінагрополітики та ЄБРР фінансують створення об''єктів зберігання та переробки зернових культур. Грант покриває будівництво міні-елеваторів (потужність від 1000 тонн), зерносушарок, млинів, комбікормових цехів. Також фінансується обладнання для лабораторного контролю якості зерна, системи автоматизації та логістики.', 'до 5,000,000 грн', 120000, '2026-08-01', 'https://minagro.gov.ua/grain-processing', 'Мінагро / ЄБРР', 'Агросектор', 'Вся Україна', 'Переробка зерна', 'APPROVED', 86, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g35_agro_drone', 'Дрони для агросектору: грант до 600,000 грн', 'Програма для придбання сільськогосподарських дронів. Обприскування, моніторинг полів, картографування та аналіз стану посівів.', 'Програма Мінцифри та Мінагрополітики підтримує впровадження безпілотних технологій у сільському господарстві. Грант покриває придбання дронів для обприскування (DJI Agras та аналоги), дронів для моніторингу та картографування, програмного забезпечення для аналізу даних, навчання операторів. Пріоритет — фермерські господарства та сервісні компанії, що надають послуги агродронів.', 'до 600,000 грн', 14400, '2026-07-15', 'https://mintsyfra.gov.ua/agro-drone-grant', 'Мінцифри / Мінагро', 'Агросектор', 'Вся Україна', 'AgriTech', 'APPROVED', 83, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

-- ОСВІТА (6 grants)
('g36_stem_school', 'STEM-лабораторія для школи: грант до 800,000 грн', 'Програма для оснащення шкільних STEM-лабораторій. Робототехніка, 3D-принтери, мікроконтролери, наукове обладнання.', 'Міносвіти спільно з USAID фінансує створення STEM-лабораторій у загальноосвітніх школах. Грант покриває обладнання для робототехніки (LEGO Education, Arduino, Raspberry Pi), 3D-принтери, лазерні різаки, наукове обладнання (мікроскопи, датчики, набори для хімічних дослідів), меблі та ремонт приміщення. Школа має забезпечити кваліфікованого вчителя та план інтеграції STEM у навчальний процес.', 'до 800,000 грн', 19200, '2026-06-01', 'https://mon.gov.ua/stem-lab-grant', 'МОН / USAID', 'Освіта', 'Вся Україна', 'STEM-освіта', 'APPROVED', 87, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g37_teacher_training', 'Підвищення кваліфікації вчителів: грант до €30,000', 'Програма Erasmus+ для стажування українських вчителів у європейських школах та університетах.', 'Програма Erasmus+ фінансує стажування українських вчителів у навчальних закладах Європи. Грант покриває витрати на проїзд, проживання, страхування, курси підвищення кваліфікації. Тривалість стажування від 2 тижнів до 3 місяців. Пріоритетні напрямки: цифрові компетенції, інклюзивна освіта, STEM-методика, проєктне навчання. Вчитель має мати від 3 років досвіду та рівень англійської від B1.', 'до €30,000', 30000, '2026-09-01', 'https://erasmusplus.org.ua/teacher-mobility', 'Erasmus+', 'Освіта', 'Вся Україна', 'Кваліфікація вчителів', 'APPROVED', 81, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g38_inclusive_ed', 'Інклюзивна освіта: грант до 600,000 грн', 'Програма ЮНІСЕФ для створення інклюзивного середовища в школах. Обладнання, навчальні матеріали, пристосування для дітей з інвалідністю.', 'ЮНІСЕФ та МОН фінансують створення інклюзивного освітнього середовища в українських школах. Грант покриває обладнання кабінетів інклюзивно-ресурсних центрів, спеціальні навчальні матеріали та допоміжні технології, архітектурну доступність (пандуси, ліфти, адаптовані санвузли), навчання педагогів інклюзивній методиці. Школа має мати учнів з особливими освітніми потребами.', 'до 600,000 грн', 14400, '2026-07-01', 'https://unicef.org/ukraine/inclusive-ed', 'ЮНІСЕФ / МОН', 'Освіта', 'Вся Україна', 'Інклюзивна освіта', 'APPROVED', 84, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g39_vocational', 'Професійна освіта: грант до €200,000', 'Програма GIZ для модернізації закладів професійної освіти. Сучасне обладнання, оновлені програми, зв''язок з бізнесом.', 'GIZ фінансує модернізацію закладів професійної (професійно-технічної) освіти в Україні. Грант покриває придбання сучасного обладнання для практичного навчання, оновлення навчальних програм відповідно до потреб ринку праці, стажування викладачів на підприємствах, створення центрів кар''єрного консультування. Заклад має мати партнерство з місцевими роботодавцями.', 'до €200,000', 200000, '2026-10-30', 'https://giz.de/ukraine-vocational', 'GIZ', 'Освіта', 'Вся Україна', 'Професійна освіта', 'APPROVED', 83, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g40_library', 'Сучасна бібліотека: грант до 500,000 грн', 'Програма для трансформації бібліотек у сучасні мультимедійні центри. Комп''ютери, інтернет, медіатеки, коворкінг-зони.', 'Програма Мінкультури та British Council фінансує модернізацію публічних бібліотек. Грант покриває комп''ютерне обладнання та швидкий інтернет, мультимедійне обладнання, е-книги та аудіокниги, меблі для коворкінг-зон та дитячих відділів, ремонт приміщень. Бібліотека має розробити план нових послуг (ІТ-курси, мовні клуби, майстер-класи) та залучення нових категорій відвідувачів.', 'до 500,000 грн', 12000, '2026-05-15', 'https://mkip.gov.ua/modern-library', 'Мінкультури / British Council', 'Освіта', 'Регіони', 'Бібліотеки', 'APPROVED', 76, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g41_digital_skills', 'Цифрова грамотність: грант до 300,000 грн', 'Програма для навчання цифрових навичок дорослих. ІТ-курси, комп''ютерна грамотність, кібербезпека, онлайн-інструменти.', 'Мінцифри фінансує проєкти з підвищення цифрової грамотності дорослого населення. Грант покриває організацію безкоштовних ІТ-курсів, придбання навчальних комп''ютерів та програмного забезпечення, розробку навчальних матеріалів українською мовою, оплату роботи тренерів. Пріоритет — курси для людей 45+, ВПО, мешканців сільської місцевості та людей з інвалідністю.', 'до 300,000 грн', 7200, '2026-08-01', 'https://mintsyfra.gov.ua/digital-skills', 'Мінцифри', 'Освіта', 'Вся Україна', 'Цифрова грамотність', 'APPROVED', 79, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

-- КУЛЬТУРА (5 grants)
('g42_museum', 'Музей майбутнього: грант до €150,000', 'Програма для цифровізації музеїв. VR/AR-екскурсії, 3D-сканування експонатів, інтерактивні виставки, онлайн-колекції.', 'Програма Українського культурного фонду та Google Arts & Culture фінансує цифровізацію українських музеїв. Грант покриває 3D-сканування та фотограмметрію експонатів, розробку VR/AR-екскурсій, створення інтерактивних мультимедійних виставок, оцифрування архівних матеріалів, розробку веб-платформи для онлайн-доступу до колекцій. Музей має мати колекцію від 500 одиниць зберігання.', 'до €150,000', 150000, '2026-09-01', 'https://ucf.org.ua/museum-future', 'УКФ / Google', 'Культура', 'Вся Україна', 'Музеї', 'APPROVED', 85, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g43_film_fund', 'Кіновиробництво: грант до 2 млн грн', 'Програма Держкіно для виробництва короткометражних та повнометражних фільмів. Пітчинг, виробництво, пост-продакшн.', 'Державне агентство з питань кіно (Держкіно) надає гранти на виробництво фільмів. Фінансуються короткометражні (до 500,000 грн) та повнометражні (до 2,000,000 грн) ігрові та документальні фільми. Грант покриває виробництво, оренду обладнання, оплату акторів та знімальної групи, пост-продакшн. Заявник має мати досвід у кіновиробництві та зареєстровану продакшн-компанію.', 'до 2,000,000 грн', 48000, '2026-06-30', 'https://dergkino.gov.ua/film-fund-2026', 'Держкіно', 'Культура', 'Вся Україна', 'Кіно', 'APPROVED', 82, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g44_music_grant', 'Музичний грант до 500,000 грн', 'Програма для запису альбомів, проведення концертів, музичних фестивалів та підтримки молодих українських музикантів.', 'Український культурний фонд фінансує музичні проєкти. Грант покриває студійний запис альбомів, організацію концертів та турів по Україні, проведення музичних фестивалів, придбання інструментів для музичних шкіл, стипендії для молодих музикантів. Пріоритет — проєкти, що популяризують українську музику та створюють нові можливості для молодих виконавців.', 'до 500,000 грн', 12000, '2026-07-15', 'https://ucf.org.ua/music-grant-2026', 'УКФ', 'Культура', 'Вся Україна', 'Музика', 'APPROVED', 78, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g45_heritage', 'Збереження спадщини: грант до €250,000', 'Програма ЮНЕСКО для реставрації об''єктів культурної спадщини, пошкоджених внаслідок війни.', 'ЮНЕСКО спільно з Мінкультури фінансує реставрацію об''єктів культурної спадщини України, пошкоджених внаслідок збройної агресії. Грант покриває обстеження та документування пошкоджень, розробку проєкту реставрації, будівельно-реставраційні роботи, консервацію артефактів, встановлення захисних систем. Об''єкт має бути включений до Державного реєстру нерухомих пам''яток України.', 'до €250,000', 250000, '2027-01-31', 'https://unesco.org/ukraine-heritage', 'ЮНЕСКО', 'Культура', 'Постраждалі регіони', 'Культурна спадщина', 'APPROVED', 93, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g46_theater', 'Театральний грант до 800,000 грн', 'Програма для постановки нових вистав, театральних фестивалів та гастрольних проєктів українських театрів.', 'Український культурний фонд підтримує розвиток театрального мистецтва. Грант покриває постановку нових вистав (режисура, сценографія, костюми, освітлення), організацію театральних фестивалів, гастролі українських театрів регіонами країни, лабораторії сучасної драматургії, адаптацію вистав для людей з порушеннями зору та слуху.', 'до 800,000 грн', 19200, '2026-05-20', 'https://ucf.org.ua/theater-2026', 'УКФ', 'Культура', 'Вся Україна', 'Театр', 'APPROVED', 77, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

-- СОЦІАЛЬНА СФЕРА (6 grants)
('g47_mental_health', 'Психічне здоров''я: грант до €80,000', 'Програма ВООЗ для створення центрів психосоціальної підтримки. Психологічна допомога ветеранам, ВПО та постраждалим від війни.', 'ВООЗ та МОЗ фінансують створення та розвиток центрів психосоціальної підтримки в Україні. Грант покриває облаштування кабінетів психологічної допомоги, підготовку спеціалістів з посттравматичного стресового розладу, впровадження програм групової та індивідуальної терапії, мобільні бригади для віддалених населених пунктів. Пріоритет — деокуповані та прифронтові території.', 'до €80,000', 80000, '2026-12-31', 'https://who.int/ukraine/mental-health', 'ВООЗ / МОЗ', 'Соціальна сфера', 'Вся Україна', 'Психічне здоров''я', 'APPROVED', 91, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g48_accessibility', 'Безбар''єрність: грант до 1 млн грн', 'Програма для забезпечення доступності публічних будівель для людей з інвалідністю. Пандуси, ліфти, тактильна навігація.', 'Мінсоцполітики та ПРООН фінансують проєкти забезпечення безбар''єрності публічних будівель. Грант покриває встановлення пандусів, підйомників та ліфтів, адаптацію санітарних приміщень, тактильну навігацію для людей з порушеннями зору, індукційні петлі для людей з порушеннями слуху, навчання персоналу. Будівля має бути у державній або комунальній власності та відвідуватися щонайменше 100 людей на день.', 'до 1,000,000 грн', 24000, '2026-10-01', 'https://msp.gov.ua/accessibility-grant', 'Мінсоцполітики / ПРООН', 'Соціальна сфера', 'Вся Україна', 'Безбар''єрність', 'APPROVED', 86, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g49_elderly_care', 'Догляд за літніми: грант до €60,000', 'Програма для розвитку послуг догляду за літніми людьми. Денні центри, мобільні бригади, навчання доглядачів.', 'Програма Червоного Хреста фінансує розвиток послуг догляду за літніми людьми в Україні. Грант покриває створення денних центрів активного довголіття, організацію мобільних бригад для надання допомоги вдома, навчання професійних доглядачів, придбання обладнання для реабілітації, організацію соціальних заходів для літніх людей. Пріоритет — сільська місцевість та малі міста.', 'до €60,000', 60000, '2026-08-15', 'https://redcross.org.ua/elderly-care', 'Червоний Хрест', 'Соціальна сфера', 'Вся Україна', 'Догляд за літніми', 'APPROVED', 80, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g50_youth_center', 'Молодіжний центр: грант до 1,500,000 грн', 'Програма для створення молодіжних просторів. Спортивні зали, арт-студії, коворкінги, навчальні кімнати та зони відпочинку.', 'Мінмолоді та ЮНІСЕФ фінансують створення молодіжних центрів у громадах України. Грант покриває ремонт та облаштування приміщення, обладнання спортивних залів, арт-студій та медіа-лабораторій, комп''ютерне обладнання, меблі для коворкінг-зон та навчальних аудиторій. Центр має забезпечити програму активностей для молоді (14-35 років) та працювати не менше 6 днів на тиждень.', 'до 1,500,000 грн', 36000, '2026-07-01', 'https://minmolod.gov.ua/youth-center-2026', 'Мінмолоді / ЮНІСЕФ', 'Соціальна сфера', 'Регіони', 'Молодіжна політика', 'APPROVED', 82, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g51_idp_support', 'Підтримка ВПО: грант до €100,000', 'Програма для інтеграції внутрішньо переміщених осіб. Житло, працевлаштування, психологічна підтримка, навчання.', 'УВКБ ООН та Мінреінтеграції фінансують проєкти інтеграції внутрішньо переміщених осіб у громадах прийняття. Грант покриває програми тимчасового та постійного житла, професійне перенавчання та працевлаштування, психосоціальну підтримку, юридичні консультації, програми соціальної адаптації. Пріоритет — громади, що прийняли значну кількість ВПО відносно місцевого населення.', 'до €100,000', 100000, '2026-11-30', 'https://unhcr.org/ukraine/idp-integration', 'УВКБ ООН', 'Соціальна сфера', 'Вся Україна', 'Підтримка ВПО', 'APPROVED', 90, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g52_disability_employment', 'Працевлаштування людей з інвалідністю: грант до 400,000 грн', 'Програма для створення інклюзивних робочих місць. Адаптація робочих місць, навчання, стажування та підтримуване працевлаштування.', 'Мінсоцполітики та ILO фінансують проєкти створення робочих місць для людей з інвалідністю. Грант покриває адаптацію робочих місць (обладнання, ергономічні меблі, допоміжні технології), професійне навчання, організацію стажувань, послуги підтримуваного працевлаштування, навчання роботодавців та колективів. Пріоритет — IT-сектор, сфера послуг та креативні індустрії.', 'до 400,000 грн', 9600, '2026-09-30', 'https://ilo.org/ukraine/disability-employment', 'ILO / Мінсоцполітики', 'Соціальна сфера', 'Вся Україна', 'Інклюзивне працевлаштування', 'APPROVED', 84, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

-- ЕНЕРГЕТИКА / ВІДНОВЛЕННЯ (5 grants)
('g53_energy_efficiency', 'Енергоефективність будівель: грант до €180,000', 'Програма KfW для утеплення житлових будинків, заміни вікон, модернізації систем опалення та встановлення теплових насосів.', 'Німецький банк розвитку KfW фінансує проєкти підвищення енергоефективності житлових будівель в Україні. Грант покриває утеплення фасадів та дахів, заміну вікон на енергоефективні, модернізацію систем опалення, встановлення теплових насосів та рекуператорів, індивідуальних теплових пунктів. ОСББ або ЖБК має бути зареєстроване та мати рішення загальних зборів.', 'до €180,000', 180000, '2026-11-01', 'https://kfw.de/ukraine-energy-efficiency', 'KfW', 'Енергетика', 'Вся Україна', 'Енергоефективність', 'APPROVED', 88, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g54_reconstruction', 'Відновлення зруйнованого житла: грант до €500,000', 'Програма ЄС для відновлення багатоквартирних будинків, пошкоджених внаслідок бойових дій.', 'Європейський Союз спільно з Мінрегіоном фінансує відновлення житлового фонду, пошкодженого внаслідок збройної агресії. Грант покриває проєктні роботи, будівельно-відновлювальні роботи, заміну інженерних мереж, благоустрій прибудинкової території. Будинок має бути включений до Реєстру пошкодженого та зруйнованого майна. Фінансування надається через місцеві громади.', 'до €500,000', 500000, '2027-06-30', 'https://eu-ua-reconstruction.org/housing', 'ЄС / Мінрегіон', 'Відновлення', 'Постраждалі регіони', 'Відновлення житла', 'APPROVED', 95, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g55_school_rebuild', 'Відновлення шкіл: грант до €300,000', 'Програма ЮНІСЕФ для ремонту та модернізації шкіл, пошкоджених війною. Укриття, вікна, системи опалення, меблі.', 'ЮНІСЕФ та МОН фінансують відновлення та модернізацію шкіл, постраждалих від війни. Грант покриває будівельно-відновлювальні роботи, облаштування безпечних укриттів, заміну вікон та дверей, відновлення систем опалення та водопостачання, придбання меблів та навчального обладнання. Пріоритет — школи у деокупованих та прифронтових територіях.', 'до €300,000', 300000, '2027-03-31', 'https://unicef.org/ukraine/school-rebuild', 'ЮНІСЕФ / МОН', 'Відновлення', 'Постраждалі регіони', 'Освітня інфраструктура', 'APPROVED', 92, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g56_hospital_equip', 'Медичне обладнання: грант до €400,000', 'Програма Японії для оснащення лікарень сучасним діагностичним та лікувальним обладнанням.', 'Уряд Японії через JICA фінансує оснащення українських лікарень сучасним медичним обладнанням. Грант покриває діагностичне обладнання (КТ, МРТ, УЗД-апарати), лабораторне обладнання, операційні блоки, реанімаційне обладнання, системи телемедицини. Лікарня має обслуговувати населення від 50,000 осіб та мати кваліфікований персонал для роботи з обладнанням.', 'до €400,000', 400000, '2026-12-31', 'https://jica.go.jp/ukraine/hospital-equip', 'JICA Японія', 'Відновлення', 'Вся Україна', 'Медична інфраструктура', 'APPROVED', 90, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

('g57_bridge_repair', 'Ремонт мостів та доріг: грант до €2,000,000', 'Програма Світового банку для відновлення транспортної інфраструктури. Мости, дороги, переїзди.', 'Світовий банк та Мінінфраструктури фінансують відновлення транспортної інфраструктури. Грант покриває проєктні та дослідницькі роботи, ремонт та реконструкцію мостів, відновлення дорожнього покриття, облаштування залізничних переїздів, встановлення дорожніх знаків та розмітки. Об''єкт має бути у державній або комунальній власності та мати значення для логістичних коридорів.', 'до €2,000,000', 2000000, '2027-06-30', 'https://worldbank.org/ukraine-transport', 'Світовий банк', 'Відновлення', 'Постраждалі регіони', 'Транспортна інфраструктура', 'APPROVED', 94, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
